const raw = JSON.parse($input.first().json.data ?? '{}');
const item = raw.items?.[0];

if (!item) {
  return [{ json: { error: 'Proyecto no encontrado', projectId: $('Webhook - Cliente desde proyecto').first().json.query.projectId } }];
}

return [{
  json: {
    internal_id: item.internal_id,
    code: item.code,
    name: item.name,
    customer: {
      id: item.customer_id,
      name: item.customer_name
    }
  }
}];
